import "./styles/MyBooks.css";

const borrowed = [
  {
    title: "Harry Potter",
    author: "J K Rowling",
    due: "25 Jan 2026",
    cover: "https://covers.openlibrary.org/b/isbn/9780439554930-L.jpg"
  },
  {
    title: "Clean Code",
    author: "Robert Martin",
    due: "28 Jan 2026",
    cover: "https://covers.openlibrary.org/b/isbn/9780132350884-L.jpg"
  }
];

function MyBooks() {
  return (
    <div className="mybooks-page">

      <h1 className="mybooks-title">📚 My Borrowed Books</h1>

      <div className="mybooks-grid">
        {borrowed.map((b, i) => (
          <div key={i} className="mybook-card">

            <img src={b.cover} alt={b.title} />

            <h3>{b.title}</h3>
            <p>{b.author}</p>
            <span className="due">Due: {b.due}</span>

            <button>Return Book</button>

          </div>
        ))}
      </div>

    </div>
  );
}

export default MyBooks;
